mapper.select:
select *
from product_distribution_operation_log
where 1 = 1

    and (
        system_spu_code like concat('%', #{keyword}, '%')
        or system_sku_code like concat('%', #{keyword}, '%')
        or seller_name like concat('%', #{keyword}, '%')
        or change_summary like concat('%', #{keyword}, '%')
    )


    and operation_type = #{operationType}


    and find_in_set(operation_type, #{operationTypes})


    and owner_type = #{ownerType}


    and spu_id = #{spuId}


    and sku_id = #{skuId}


    and operator_name like concat('%', #{operatorName}, '%')


    and operation_time >= #{params.beginTime}


    and operation_time <= #{params.endTime}

order by operation_time desc, log_id desc
